import { createContext } from 'reka-ui'
import type { HeatmapDataRootContext } from './types'

export const [injectHeatmapDataRootContext, provideHeatmapDataRootContext] =
  createContext<HeatmapDataRootContext>('HeatmapDataRootContext')

export const useHeatmapDataRootContext = () => {
  const ctx = injectHeatmapDataRootContext()

  if (!ctx) {
    throw new Error(
      '[Heatmap] Missing required context. Ensure this component is used within <Heatmap />',
    )
  }

  return ctx
}

import { getActualStartDate, getActualEndDate, createHeatmapCells } from './utils'
import { computed, type MaybeRefOrGetter, toValue } from 'vue'
import { useGithubProfile } from '@/composables/use-github-profile'

interface UseHeatmapOptions {
  githubUsername: MaybeRefOrGetter<string | undefined>
  data: MaybeRefOrGetter<Record<string, number>>
  startDate?: MaybeRefOrGetter<Date | undefined>
  endDate?: MaybeRefOrGetter<Date | undefined>
  rows: MaybeRefOrGetter<number>
  cols: MaybeRefOrGetter<number>
  maxLevel: MaybeRefOrGetter<number>
  getLevel: MaybeRefOrGetter<(count: number) => number>
  dayMs: number
}

/**
 * Main composable for the contribution heatmap.
 * Handles data fetching (GitHub or local), date range normalization, and cell generation.
 */
export function useHeatmap(options: UseHeatmapOptions) {
  const resolvedUsername = computed(() => toValue(options.githubUsername))
  const resolvedData = computed(() => toValue(options.data))
  const resolvedStartDate = computed(() => toValue(options.startDate))
  const resolvedEndDate = computed(() => toValue(options.endDate))
  const resolvedRows = computed(() => toValue(options.rows))
  const resolvedCols = computed(() => toValue(options.cols))
  const resolvedMaxLevel = computed(() => toValue(options.maxLevel))
  const resolvedGetLevel = computed(() => toValue(options.getLevel))

  const {
    profile,
    contributionData: githubContributionData,
    totalContributions: githubTotalContributions,
    isLoading: isGithubLoading,
    isError: isGithubError,
  } = useGithubProfile(resolvedUsername)

  const actualStartDate = computed(() => {
    if (resolvedStartDate.value) return resolvedStartDate.value
    if (resolvedUsername.value) {
      const d = new Date()
      d.setFullYear(d.getFullYear() - 1)
      d.setHours(0, 0, 0, 0)
      return d
    }
    return getActualStartDate(resolvedStartDate.value)
  })

  const actualEndDate = computed(() => {
    if (resolvedEndDate.value) return resolvedEndDate.value
    if (resolvedUsername.value) {
      const d = new Date()
      d.setHours(23, 59, 59, 999)
      return d
    }
    return getActualEndDate(resolvedEndDate.value)
  })

  const isLoading = computed(() => (resolvedUsername.value ? isGithubLoading.value : false))
  const isError = computed(() => (resolvedUsername.value ? isGithubError.value : false))

  const contributionData = computed(() => {
    if (resolvedUsername.value) {
      return githubContributionData.value
    }
    return resolvedData.value
  })

  const totalContributions = computed(() => {
    if (resolvedUsername.value) {
      return githubTotalContributions.value
    }
    return Object.values(contributionData.value).reduce((a, b) => a + b, 0)
  })

  const cells = computed(() =>
    createHeatmapCells({
      startDate: actualStartDate.value,
      endDate: actualEndDate.value,
      data: contributionData.value,
      rows: resolvedRows.value,
      cols: resolvedCols.value,
      dayMs: options.dayMs,
      maxLevel: resolvedMaxLevel.value,
      getLevel: resolvedGetLevel.value,
    }),
  )

  return {
    actualStartDate,
    actualEndDate,
    contributionData,
    totalContributions,
    isLoading,
    isError,
    profile,
    cells,
  }
}

import type { ComputedRef, Ref, ShallowRef } from 'vue'
import type { GitHubProfile } from '@/composables/use-github-profile'

/**
 * A 5-element tuple of Tailwind CSS class strings that map directly to
 * contribution levels 0 (no activity) through 4 (highest activity).
 *
 * Example (blue palette):
 * ```ts
 * ['bg-muted', 'bg-blue-200', 'bg-blue-400', 'bg-blue-600', 'bg-blue-800']
 * ```
 */
export type HeatmapPalette = [string, string, string, string, string]

export type HeatmapProps = {
  /**
   * The start date of the heatmap.
   * @default start of the current year
   */
  startDate?: Date
  /**
   * The end date of the heatmap.
   * @default end of the current year
   */
  endDate?: Date
  /**
   * Optional data to populate the heatmap cells. Key is ISO date string (YYYY-MM-DD), value is contribution count.
   * Example: `{ "2024-01-01": 5, "2024-01-02": 10 }`
   * @default {}
   */
  data?: Record<string, number>
  /**
   * Number of rows in the heatmap grid (typically 7 for days of the week).
   * @default 7
   */
  rows?: number
  /**
   * Number of columns in the heatmap grid.
   * @default 52
   */
  cols?: number
  /**
   * Maximum level of contributions (e.g., 4 for 0-4 levels).
   * @default 4
   */
  maxLevel?: number
  /**
   * Github username to fetch contributions for.
   * @default undefined
   */
  githubUsername?: string
  /**
   * Function to determine the contribution level for a given count.
   * @param count - The number of contributions.
   * @returns The level (0 to maxLevel).
   * @default (count) => Math.min(Math.floor(count / 2), maxLevel)
   */
  getLevel?: (count: number) => number
  /**
   * Function to determine the contribution count for a given level and index.
   * @param level - The contribution level.
   * @param index - The index of the level.
   * @returns The minimum contributions for this level.
   * @default (level) => level * 2
   */
  getContributionsForLevel?: (level: number, index: number) => number
  /**
   * A color palette for the heatmap cells expressed as Tailwind CSS class
   * strings, one per level (index 0 = no activity, index 4 = highest activity).
   *
   * @default ['bg-muted', 'bg-emerald-200', 'bg-emerald-400', 'bg-emerald-600', 'bg-emerald-800']
   */
  palette?: HeatmapPalette
}

export type HeatmapCellProps = {
  /**
   * The data for the individual heatmap cell.
   */
  cell: HeatmapCellProp
}

export type HeatmapLegendProps = {
  /**
   * Optional label text shown on the left (e.g. "Learn how we count contributions").
   */
  label?: string
  /**
   * Specific levels to display in the legend.
   * If not provided, it will show all levels from 0 to maxLevel.
   */
  levels?: number[]
}

export type HeatmapWeekdaysProps = {
  /**
   * Whether to show all weekday labels or just the standard ones (Mon, Wed, Fri).
   * @default false
   */
  showAll?: boolean
}

export type HeatmapEmits = {
  /**
   * Fired when a cell is clicked.
   * @property cell - The data of the clicked cell.
   */
  'click:cell': [cell: HeatmapCellProp]
}

export type HeatmapDataRootContext = {
  /** The unique ID of the heatmap. */
  id: string
  /** The start date used for the grid. */
  startDate: ComputedRef<Date> | Ref<Date>
  /** The end date used for the grid. */
  endDate: ComputedRef<Date> | Ref<Date>
  /** The flat list of all cells in the heatmap. */
  cells: ComputedRef<HeatmapCellProp[]> | Ref<HeatmapCellProp[]>
  /** The contribution data mapping. */
  data: ComputedRef<Record<string, number>> | Ref<Record<string, number>>
  /** Total contributions count. */
  totalContributions: ComputedRef<number | undefined> | Ref<number | undefined>
  /** Whether the data is currently loading. */
  isLoading: ComputedRef<boolean> | Ref<boolean>
  /** Whether there was an error fetching data. */
  isError: ComputedRef<boolean> | Ref<boolean>
  /** The GitHub user profile data. */
  profile?: ShallowRef<GitHubProfile | null>
  /** Number of rows in the grid. */
  rows: ComputedRef<number> | Ref<number>
  /** Number of columns in the grid. */
  cols: ComputedRef<number> | Ref<number>
  /** Milliseconds in a day. */
  dayMs: number
  /** Maximum contribution level. */
  maxLevel: ComputedRef<number> | Ref<number>
  /** Function to calculate level from count. */
  getLevel: ComputedRef<(count: number) => number> | Ref<(count: number) => number>
  /** Function to calculate count from level. */
  getContributionsForLevel:
    | ComputedRef<(level: number, index: number) => number>
    | Ref<(level: number, index: number) => number>
  /** Optional click handler for cells. */
  onCellClick?: (cell: HeatmapCellProp) => void
  /** Active color palette (Tailwind class strings for levels 0–4). */
  palette: ComputedRef<HeatmapPalette> | Ref<HeatmapPalette>
}

export type HeatmapCellProp = {
  /** ISO date string key (YYYY-MM-DD). */
  key: string
  /** Row index in the grid. */
  row: number
  /** Column index in the grid. */
  col: number
  /** The actual Date object. */
  date: Date
  /** Formatted date label (e.g. "Jan 1, 2024"). */
  dateLabel: string
  /** Formatted weekday label (e.g. "Mon"). */
  weekdayLabel: string
  /** Number of contributions on this day. */
  contributions: number
  /** The calculated level for this day. */
  level: number
}

import type { HeatmapCellProp } from './types'
import { useDateFormat } from '@vueuse/core'

/**
 * Returns the date for the start of the week (Sunday) for a given date.
 */
export function startOfWeek(date: Date): Date {
  const d = new Date(date)
  d.setHours(12, 0, 0, 0)
  d.setDate(d.getDate() - d.getDay())
  return d
}

/**
 * Groups a flat list of heatmap cells into a 2D array [row][col].
 */
export function groupCellsByRow(cells: HeatmapCellProp[], rows: number): HeatmapCellProp[][] {
  const grid: HeatmapCellProp[][] = Array.from({ length: rows }, () => [])
  for (const cell of cells) {
    if (cell.row < rows) {
      grid[cell.row]!.push(cell)
    }
  }
  return grid
}

/**
 * Generates month markers based on the first cell of each column.
 */
export function getMonthMarkers(cells: HeatmapCellProp[], cols: number): (string | null)[] {
  const labels: (string | null)[] = Array.from({ length: cols }, () => null)
  let lastMonth = -1

  for (let col = 0; col < cols; col++) {
    const cell = cells.find(c => c.col === col && c.row === 0)
    if (cell) {
      const month = cell.date.getMonth()
      if (month !== lastMonth) {
        labels[col] = cell.date.toLocaleString('default', { month: 'short' })
        lastMonth = month
      }
    }
  }

  return labels
}

/**
 * Generates weekday labels based on the number of rows and display preference.
 */
export function getWeekdayLabels(rows: number, showAll: boolean): string[] {
  const WEEKDAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']
  if (rows !== 7) return []
  return WEEKDAY_LABELS.map((day, index) => {
    if (showAll) return day
    // Standard heatmap style: Mon, Wed, Fri
    return [1, 3, 5].includes(index) ? day : ''
  })
}

/**
 * Formats a date for heatmap keys and labels.
 */
export function formatHeatmapDate(date: Date, format: 'key' | 'label' | 'weekday' = 'key'): string {
  if (format === 'key') return useDateFormat(date, 'YYYY-MM-DD').value
  if (format === 'label') return useDateFormat(date, 'MMM D, YYYY').value
  return useDateFormat(date, 'ddd').value
}

/**
 * Calculates the actual start date for the heatmap, defaulting to the start of the current year.
 */
export function getActualStartDate(startDate?: Date): Date {
  if (startDate) return startDate
  const d = new Date()
  d.setMonth(0, 1)
  d.setHours(0, 0, 0, 0)
  return d
}

/**
 * Calculates the actual end date for the heatmap, defaulting to the end of the current year.
 */
export function getActualEndDate(endDate?: Date): Date {
  if (endDate) return endDate
  const d = new Date()
  d.setMonth(11, 31)
  d.setHours(23, 59, 59, 999)
  return d
}

export function getLevels(
  maxLevelOrLevels: number | number[],
  getContributionsForLevel: (level: number, index: number) => number,
) {
  const levels = Array.isArray(maxLevelOrLevels)
    ? maxLevelOrLevels
    : Array.from({ length: maxLevelOrLevels + 1 }, (_, i) => i)

  return levels.map(i => ({
    level: i,
    contributions: getContributionsForLevel(i, 0),
  }))
}

/**
 * Options for creating heatmap cells.
 */
export interface CreateHeatmapCellsOptions {
  /** The start date for the heatmap range. */
  startDate: Date
  /** The end date for the heatmap range. */
  endDate: Date
  /** The contribution data mapping. */
  data: Record<string, number>
  /** Number of rows in the grid. */
  rows: number
  /** Number of columns in the grid. */
  cols: number
  /** Milliseconds in a day. */
  dayMs: number
  /** Maximum level of contributions. */
  maxLevel: number
  /** Function to determine the level for a count. */
  getLevel: (count: number) => number
}

/**
 * Generates a flat array of cell data for the heatmap grid.
 */
export function createHeatmapCells(options: CreateHeatmapCellsOptions): HeatmapCellProp[] {
  const { startDate, endDate, data, rows, cols, dayMs, getLevel } = options
  const cells: HeatmapCellProp[] = []

  const gridStart = startOfWeek(startDate)
  let currentCol = 0
  const currentDay = new Date(gridStart)
  currentDay.setHours(0, 0, 0, 0)

  const endTime = endDate.getTime()

  while (currentCol < cols) {
    const row = currentDay.getDay()

    if (row < rows) {
      const dateKey = formatHeatmapDate(currentDay, 'key')
      const count = data[dateKey] || 0

      cells.push({
        key: dateKey,
        date: new Date(currentDay),
        row,
        col: currentCol,
        contributions: count,
        level: getLevel(count),
        dateLabel: formatHeatmapDate(currentDay, 'label'),
        weekdayLabel: formatHeatmapDate(currentDay, 'weekday'),
      })
    }

    currentDay.setDate(currentDay.getDate() + 1)
    if (currentDay.getDay() === 0) {
      currentCol++
    }

    // Safety break to prevent infinite loops if misconfigured
    if (currentDay.getTime() > endTime + dayMs * 7) {
      break
    }
  }

  return cells
}

import type { Ref } from 'vue'
import { createContext } from 'reka-ui'

export interface AutocompleteContext {
  searchTerm: Ref<string>
}

const [injectAutocompleteContext, provideAutocompleteContext] =
  createContext<AutocompleteContext>('AutocompleteContext')

export { provideAutocompleteContext }

const requiredKeys: (keyof AutocompleteContext)[] = ['searchTerm']
/**
 * Hook to access the Autocomplete context within sub-components.
 *
 * @returns The shared Autocomplete context.
 * @throws Error if called outside of an `<Autocomplete>` component tree.
 */
export function useAutocompleteContext(): AutocompleteContext {
  const ctx = injectAutocompleteContext()

  if (!ctx) {
    throw new Error(
      '[Autocomplete] useAutocompleteContext() was called outside of an <Autocomplete> component.\n' +
        'Make sure your component is rendered inside an <Autocomplete> root.',
    )
  }
  const missingKeys = requiredKeys.filter(key => ctx[key] === undefined)
  if (missingKeys.length > 0) {
    throw new Error(
      `[Autocomplete] Missing required context property: "${missingKeys.join(', ')}".`,
    )
  }
  return ctx
}

