import type { ShowMoreRootContext } from './types'
import { createContext } from 'reka-ui'

export const [injectShowMoreRootContext, provideShowMoreRootContext] =
  createContext<ShowMoreRootContext>('ShowMoreRootContext')

export const [injectShowMoreItemContext, provideShowMoreItemContext] = createContext<{
  value: string
  isTruncated: boolean
}>('ShowMoreItemContext')

const requiredKeys: (keyof ShowMoreRootContext)[] = [
  'threshold',
  'truncationType',
  'fade',
  'forceMount',
  'showToggle',
  'open',
  'lineHeight',
]

export function useShowMoreRootContext(): ShowMoreRootContext {
  const ctx = injectShowMoreRootContext()

  if (!ctx) {
    throw new Error('[ShowMore] useShowMoreRootContext() was called outside of <ShowMore>.')
  }

  const missingKeys = requiredKeys.filter(key => ctx[key] === undefined)
  if (missingKeys.length > 0) {
    throw new Error(`[ShowMore] Missing required context property: "${missingKeys.join(', ')}".`)
  }

  return ctx
}

export function useShowMoreItemContext() {
  const ctx = injectShowMoreItemContext()
  if (!ctx) {
    throw new Error('[ShowMore] useShowMoreItemContext() was called outside of <ShowMoreItem>.')
  }

  if (ctx.value === undefined || ctx.value === null) {
    throw new Error('[ShowMore] Missing required context property: "value" from <ShowMoreItem>.')
  }

  if (ctx.isTruncated === undefined) {
    throw new Error(
      '[ShowMore] Missing required context property: "isTruncated" from <ShowMoreItem>.',
    )
  }

  return ctx
}

import type { Ref } from 'vue'
import { onMounted, ref } from 'vue'

/**
 * Composable to detect if the user is on a Mac.
 * Uses a robust platform check with fallbacks for modern and legacy browsers.
 * Initialized to false to avoid SSR hydration mismatches.
 */
export function useIsMac(): Ref<boolean> {
  const isMac = ref(false)
  onMounted(() => {
    const nav = navigator as any
    const platform = nav.userAgentData?.platform ?? nav.platform ?? nav.userAgent
    isMac.value = String(platform).toUpperCase().includes('MAC')
  })
  return isMac
}

import { computed, type MaybeRefOrGetter, toValue } from 'vue'
import { useFetch } from '@vueuse/core'

export interface GitHubProfile {
  login: string
  name: string | null
  avatar_url: string
  bio: string | null
  location: string | null
  blog: string | null
  company: string | null
  followers: number
  following: number
  public_repos: number
  public_gists: number
  twitter_username: string | null
  html_url: string
}

export interface GitHubContributionDay {
  date: string
  contributionCount: number
  color?: string
  contributionLevel?: string
}

export interface GitHubContributionsResponse {
  contributions: GitHubContributionDay[][]
  totalContributions: number
}

export interface UseGithubProfileOptions {
  username: MaybeRefOrGetter<string | undefined>
}

/**
 * Composable for fetching GitHub profile and contribution data.
 */
export function useGithubProfile(username: MaybeRefOrGetter<string | undefined>) {
  const resolvedUsername = computed(() => toValue(username))

  // Fetch GitHub User Profile
  const profileUrl = computed(() =>
    resolvedUsername.value
      ? `https://api.github.com/users/${resolvedUsername.value}`
      : (null as unknown as string),
  )

  const {
    data: profile,
    isFetching: isLoadingProfile,
    error: profileError,
  } = useFetch(profileUrl, {
    refetch: true,
  })
    .get()
    .json<GitHubProfile>()

  // Fetch GitHub Contributions
  const contributionsUrl = computed(() =>
    resolvedUsername.value
      ? `https://github-contributions-api.deno.dev/${resolvedUsername.value}.json`
      : (null as unknown as string),
  )

  const {
    data: fetchedData,
    isFetching: isLoadingContributions,
    error: contributionsError,
  } = useFetch(contributionsUrl, {
    refetch: true,
  })
    .get()
    .json<GitHubContributionsResponse>()

  const isLoading = computed(() => isLoadingProfile.value || isLoadingContributions.value)
  const isError = computed(() => !!profileError.value || !!contributionsError.value)

  const contributionData = computed(() => {
    if (resolvedUsername.value && fetchedData.value?.contributions) {
      return fetchedData.value.contributions.flat().reduce(
        (acc, curr) => {
          acc[curr.date] = curr.contributionCount
          return acc
        },
        {} as Record<string, number>,
      )
    }
    return {}
  })

  const totalContributions = computed(() => {
    if (resolvedUsername.value && fetchedData.value?.totalContributions !== undefined) {
      return fetchedData.value.totalContributions
    }
    return 0
  })

  return {
    profile,
    contributionData,
    totalContributions,
    isLoading,
    isError,
  }
}
